#requires -Version 5.1
<# Created by Dewald Pretorius. Read-only Microsoft 365 tenant security validator using Microsoft Graph. #>
[CmdletBinding()]param([string]$OutputPath=(Join-Path ([Environment]::GetFolderPath('Desktop')) 'M365_Tenant_Security_Validation'))
$ErrorActionPreference='Stop';New-Item -ItemType Directory $OutputPath -Force|Out-Null;$s=Get-Date -Format yyyyMMdd_HHmmss
try{if(-not(Get-Command Get-MgContext -ErrorAction SilentlyContinue)){Write-Error 'Microsoft Graph PowerShell is required.';exit 3};$ctx=Get-MgContext;if(-not$ctx){Write-Error 'Connect-MgGraph before running.';exit 3};$users=@();if(Get-Command Get-MgUser -ErrorAction SilentlyContinue){$users=@(Get-MgUser -All -Property Id,UserPrincipalName,AccountEnabled,UserType|Select-Object UserPrincipalName,AccountEnabled,UserType)};$ca=@();if(Get-Command Get-MgIdentityConditionalAccessPolicy -ErrorAction SilentlyContinue){$ca=@(Get-MgIdentityConditionalAccessPolicy -All|Select-Object DisplayName,State)};$warnings=@();if(@($ca|Where-Object State -eq 'enabled').Count-eq0){$warnings+='No enabled Conditional Access policies were returned.'};if(@($users|Where-Object{$_.UserType-eq'Guest'-and$_.AccountEnabled}).Count-gt50){$warnings+='More than 50 enabled guest accounts were detected.'};[ordered]@{Generated=(Get-Date);TenantId=$ctx.TenantId;UserCount=$users.Count;EnabledGuestCount=@($users|Where-Object{$_.UserType-eq'Guest'-and$_.AccountEnabled}).Count;ConditionalAccessPolicies=$ca;Warnings=$warnings}|ConvertTo-Json -Depth 6|Set-Content (Join-Path $OutputPath "tenant_security_$s.json");if($warnings.Count){exit 1};exit 0}catch{Write-Error $_;exit 5}
